('ae37c209-5ad4-480d-b075-b13bfc69c547', 'ba1a1cfa-884d-4aad-b2ee-c8a2f458d822', 'd6c8c76c-ffa9-4c03-8985-bbdaf5ff88e7', '12c958f5-3e65-4109-9af0-5606d49005c7', 7, 'The linear equation in one variable x is:'::text, '[{"key": "A", "text": "ax + b = 0"}, {"key": "B", "text": "ax2 + bx + c = 0"}, {"key": "C", "text": "ax + by + c = 0"}, {"key": "D", "text": "ax2 + by2 + c = 0"}]'::jsonb, 'A', 'extracted', 7),
('6fbe1512-f8bb-4b1e-852d-a1bcd928a99d', 'ba1a1cfa-884d-4aad-b2ee-c8a2f458d822', 'd6c8c76c-ffa9-4c03-8985-bbdaf5ff88e7', '12c958f5-3e65-4109-9af0-5606d49005c7', 8, 'An inconsistent equation is that whose solution set is:'::text, '[{"key": "A", "text": "Empty"}, {"key": "B", "text": "Not empty"}, {"key": "C", "text": "Zero"}, {"key": "D", "text": "Positive"}]'::jsonb, 'A', 'extracted', 7),
('85d53506-8205-4c63-9888-6f91344bc7fe', 'ba1a1cfa-884d-4aad-b2ee-c8a2f458d822', 'd6c8c76c-ffa9-4c03-8985-bbdaf5ff88e7', '12c958f5-3e65-4109-9af0-5606d49005c7', 9, 'x = a is equivalent to:'::text, '[{"key": "A", "text": "x = a or x = -a"}, {"key": "B", "text": "1 1 x or x a a - = ="}, {"key": "C", "text": "1 x a or x a - = ="}, {"key": "D", "text": "None of these"}]'::jsonb, 'A', 'extracted', 7),
('12eff0e5-fa7c-4ce2-95ac-779cf9f2fba9', 'ba1a1cfa-884d-4aad-b2ee-c8a2f458d822', 'd6c8c76c-ffa9-4c03-8985-bbdaf5ff88e7', '12c958f5-3e65-4109-9af0-5606d49005c7', 10, 'A linear inequality in one variable x is:'::text, '[{"key": "A", "text": "a x + b > 0, a ≠ 0"}, {"key": "B", "text": "ax2 + bx + c < 0, a ≠ 0"}, {"key": "C", "text": "ax +by + c > 0, a ≠ 0"}, {"key": "D", "text": "ax2 + by2 + c < 0, a ≠ 0"}]'::jsonb, 'A', 'extracted', 7),
('da40d995-7b53-4464-a43c-c9fbad0b08d3', 'ba1a1cfa-884d-4aad-b2ee-c8a2f458d822', 'd6c8c76c-ffa9-4c03-8985-bbdaf5ff88e7', '12c958f5-3e65-4109-9af0-5606d49005c7', 11, 'Law of Trichotomy is ... (a,b R) in'::text, '[{"key": "A", "text": "a < b or a = b or a > b"}, {"key": "B", "text": "a < b or a = b"}, {"key": "C", "text": "a < b or a > b"}, {"key": "D", "text": "None of these"}]'::jsonb, 'A', 'extracted', 7),
('fbabfe14-1a24-42df-bad4-8061b04cd14e', 'ba1a1cfa-884d-4aad-b2ee-c8a2f458d822', 'd6c8c76c-ffa9-4c03-8985-bbdaf5ff88e7', '12c958f5-3e65-4109-9af0-5606d49005c7', 12, 'Transitive law is____'::text, '[{"key": "A", "text": "a < b and b < c, then a < c"}, {"key": "B", "text": "a > b and b < c, then a > c"}, {"key": "C", "text": "a > b and b < c, then a = c"}, {"key": "D", "text": "None of these"}]'::jsonb, 'A', 'extracted', 7),
('ba2bab87-febd-4bfe-b018-60c4c2d58feb', 'ba1a1cfa-884d-4aad-b2ee-c8a2f458d822', 'd6c8c76c-ffa9-4c03-8985-bbdaf5ff88e7', '12c958f5-3e65-4109-9af0-5606d49005c7', 13, 'If a > b, c > 0 then:'::text, '[{"key": "A", "text": "a c < bc"}, {"key": "B", "text": "ac > bc"}, {"key": "C", "text": "ac = bc"}, {"key": "D", "text": "ac ≤ bc"}]'::jsonb, 'B', 'extracted', 7),
('e75e5d56-00da-4cce-a7eb-066a35bfbceb', 'ba1a1cfa-884d-4aad-b2ee-c8a2f458d822', 'd6c8c76c-ffa9-4c03-8985-bbdaf5ff88e7', '12c958f5-3e65-4109-9af0-5606d49005c7', 14, 'If a > b, c > 0 then:'::text, '[{"key": "A", "text": "a b c c >"}, {"key": "B", "text": "a b c c <"}, {"key": "C", "text": "a b c c ="}, {"key": "D", "text": "b b c c ≠"}]'::jsonb, 'A', 'extracted', 7),
('4e8bad32-7475-41c4-a9fc-664af57b3297', 'ba1a1cfa-884d-4aad-b2ee-c8a2f458d822', 'd6c8c76c-ffa9-4c03-8985-bbdaf5ff88e7', '12c958f5-3e65-4109-9af0-5606d49005c7', 15, 'If a > b, c < 0, then:'::text, '[{"key": "A", "text": "a b c c <"}, {"key": "B", "text": "a b c c >"}, {"key": "C", "text": "a b c c ="}, {"key": "D", "text": "a b c c ≤"}]'::jsonb, 'A', 'extracted', 7),
('5806c817-5277-4509-a7a1-09663b27b807', 'ba1a1cfa-884d-4aad-b2ee-c8a2f458d822', 'd6c8c76c-ffa9-4c03-8985-bbdaf5ff88e7', '12c958f5-3e65-4109-9af0-5606d49005c7', 16, 'If a, b in R then: b ≠ 0'::text, '[{"key": "A", "text": "a a b b ="}, {"key": "B", "text": "a ab b ="}, {"key": "C", "text": "a b a b + = +"}, {"key": "D", "text": "a b a b - = -"}]'::jsonb, 'A', 'extracted', 7);
