('a2ba4a20-efa4-488d-b09d-bb28129472eb', 'ba1a1cfa-884d-4aad-b2ee-c8a2f458d822', 'd6c8c76c-ffa9-4c03-8985-bbdaf5ff88e7', '12c958f5-3e65-4109-9af0-5606d49005c7', 25, 'x = x + 5 is ___ equation:'::text, '[{"key": "A", "text": "Identity"}, {"key": "B", "text": "Conditional"}, {"key": "C", "text": "Inconsistent"}, {"key": "D", "text": "None"}]'::jsonb, 'C', 'extracted', 7),
('0a109bca-3b53-4481-b2bf-c7542e027ca7', 'ba1a1cfa-884d-4aad-b2ee-c8a2f458d822', 'd6c8c76c-ffa9-4c03-8985-bbdaf5ff88e7', '12c958f5-3e65-4109-9af0-5606d49005c7', 26, 'Equations having exactly the same solution are called ___ equations.'::text, '[{"key": "A", "text": "equivalent"}, {"key": "B", "text": "Linear"}, {"key": "C", "text": "Inconsistent"}]'::jsonb, 'A', 'extracted', 7),
('88be1259-ef2c-41b4-a671-ad64110545f7', 'ba1a1cfa-884d-4aad-b2ee-c8a2f458d822', 'd6c8c76c-ffa9-4c03-8985-bbdaf5ff88e7', '12c958f5-3e65-4109-9af0-5606d49005c7', 27, 'A solution that does not satisfy the original equation is called ____ solution:'::text, '[{"key": "A", "text": "Extraneous"}, {"key": "B", "text": "Root"}, {"key": "C", "text": "General"}, {"key": "D", "text": "Proper"}]'::jsonb, 'A', 'extracted', 7),
('c8e1313b-fe92-4a67-b6b4-61ef0504b0c2', 'ba1a1cfa-884d-4aad-b2ee-c8a2f458d822', '1d28c0db-6fd1-4cca-acde-9e58dcd97d44', '12c958f5-3e65-4109-9af0-5606d49005c7', 1, 'If (x-1, y+1) = (0, 0), then (x, y) is:'::text, '[{"key": "A", "text": "(1, -1)"}, {"key": "B", "text": "(-1, 1)"}, {"key": "C", "text": "(1, 1)"}, {"key": "D", "text": "(-1, -1)"}]'::jsonb, 'A', 'extracted', 8),
